import {
  MapContainer,
  TileLayer,
  Polyline,
  useMap,
} from "react-leaflet";
import { useState, useEffect } from "react";
import PlaneMarker from "../components/PlaneMarker";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

function FixMap() {
  const map = useMap();
  setTimeout(() => map.invalidateSize(), 100);
  return null;
}

export default function Dashboard() {
  const [flightNo, setFlightNo] = useState("");
  const [position, setPosition] = useState([20, 77]);
  const [flightData, setFlightData] = useState(null);
  const [trail, setTrail] = useState([]);
  const [loading, setLoading] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [hasPosition, setHasPosition] = useState(false);

  const fetchFlight = async () => {
    try {
      if (!flightNo.trim()) return;

      setLoading(true);
      setHasSearched(true);

      const res = await fetch(
        `http://localhost:5000/api/flights/${flightNo}`
      );
      const data = await res.json();

      // 🔥 fallback if API fails
      if (data.error) {
        const fake = {
          callsign: "DEMO123",
          country: "Demo Airspace",
          latitude: 28.6,
          longitude: 77.2,
          altitude: 11000,
          velocity: 230,
          heading: 120,
        };

        setFlightData(fake);
        setPosition([fake.latitude, fake.longitude]);
        setTrail((prev) => [...prev, [fake.latitude, fake.longitude]]);
        return;
      }

      const { latitude, longitude } = data;

      if (!latitude || !longitude || isNaN(latitude) || isNaN(longitude)) {
        return;
      }

      if (!hasPosition) {
        setPosition([latitude, longitude]);
        setHasPosition(true);
      } else {
        setPosition((prev) => [
          prev[0] + (latitude - prev[0]) * 0.3,
          prev[1] + (longitude - prev[1]) * 0.3,
        ]);
      }

      setFlightData(data);

      setTrail((prev) => {
        const updated = [...prev, [latitude, longitude]];
        return updated.slice(-20);
      });
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!flightData) return;
    const interval = setInterval(fetchFlight, 4000);
    return () => clearInterval(interval);
  }, [flightData]);

  return (
    <div className="dashboard">
      {/* PANEL */}
      <div className="panel">
        <h1 className="title">✈️ Flight Tracker</h1>

        <div className="search-box">
          <input
            value={flightNo}
            onChange={(e) => setFlightNo(e.target.value)}
            placeholder="Enter callsign (QTR8964)"
          />

          <button onClick={fetchFlight}>
            {loading ? <span className="dots">Tracking</span> : "Track"}
          </button>
        </div>

        {!flightData && hasSearched && !loading && (
          <p className="status">No live tracking</p>
        )}

        {!hasSearched && (
          <p className="hint">Try: AIC • QTR • UAE • BAW</p>
        )}

        {flightData && (
          <div className="info">
            <h2>{flightData.callsign}</h2>
            <p>{flightData.country}</p>
            <div className="meta">
              <span>Alt {Math.round(flightData.altitude)}</span>
              <span>Speed {Math.round(flightData.velocity)}</span>
            </div>
          </div>
        )}
      </div>

      {/* MAP */}
      <MapContainer
        center={position}
        zoom={5}
        className="map"
      >
        <FixMap />

        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        <PlaneMarker position={position} flightData={flightData} />

        {trail.length > 1 && (
          <Polyline
            positions={trail}
            pathOptions={{
              color: "#ff2a2a",
              weight: 3,
              opacity: 0.9,
            }}
          />
        )}
      </MapContainer>
    </div>
  );
}
